mapper.select:
SELECT a.id, process_code, process_name, process_type, source, destination, a.create_by, a.create_time, a.update_by, a.update_time, b.user_name as create_name, c.user_name as update_name, d.DICT_LABEL as process_type_label, e.DICT_LABEL as source_label, f.DICT_LABEL as destination_label FROM m_operation_process a left join sys_user b on a.create_by = b.id left join sys_user c on a.update_by = c.id left join M_DICT_DATA d ON a.PROCESS_TYPE=d.DICT_VALUE and d.DICT_TYPE='PROCESS_TYPE' left join M_DICT_DATA e ON a.source=e.DICT_VALUE and e.DICT_TYPE='WORK_ORIGN' left join M_DICT_DATA f ON a.destination=f.DICT_VALUE and f.DICT_TYPE='WORK_ORIGN'
and process_name like #{processName}
order by CREATE_TIME desc

SELECT a.id, process_code, subprocess_code, subprocess_name, source, description, cargo_volume, a.create_by, a.create_time, a.update_by, a.update_time, b.user_name as create_name, c.user_name as update_name, e.DICT_LABEL as source_label, f.DICT_LABEL as destination_Label FROM m_operation_subprocess a inner join sys_user b on a.create_by = b.id left join sys_user c on a.update_by = c.id left join M_DICT_DATA e ON a.source=e.DICT_VALUE and e.DICT_TYPE='WORK_ORIGN' left join M_DICT_DATA f ON a.description=f.DICT_VALUE and f.DICT_TYPE='WORK_ORIGN'
and process_code=#{processCode}
and subprocess_name like #{processName}
order by CREATE_TIME desc

SELECT t.id, t.process_code, t.process_name, t.process_type, t.source, t.destination, t.create_by, t.create_time, t.update_by, t.update_time, b.user_name as create_name, c.user_name as update_name FROM m_operation_process t inner join sys_user b on t.create_by = b.id left join sys_user c on t.update_by = c.id
and PROCESS_NAME like #{processName}
order by CREATE_TIME desc
